%%%%%%%%%% Function sttImg3.m %%%%%%%%%%% Varian Statistics Image, ver.3%% Kei Nakamura% Created on Friday, March 24th 2006.% Modified on Thursday, April 20th 2006.%% function stt = sttImg3(img)% does analysis on image.%% 1,2: E(x) of x and y% 3,4: index for peak of x and y% 5,6: rms for x and yfunction stt = sttImg3(img)img = real(sqrt(img)).^2 + 1;       % to avoid /0.[dy,dx] = size(img);% for xposX = meshgrid(1:dx,1);imgX = sum(img);    bbb(1) = sum(imgX); % sum of rawbbb(2) = sum(posX.*imgX); % E(x)*sumbbb(3) = sum(posX.*posX.*imgX); % E(x^2)*sumbbb(4) = bbb(1)*bbb(3)-bbb(2)^2; %V*sum^2stt(1) = bbb(2)/bbb(1);stt(5) = sqrt(bbb(4))/bbb(1);[aa bb] = max(imgX);stt(3) = bb; % for yimgY = sum(img,2);posY = meshgrid(1:dy,1)';aaa(1) = sum(imgY); % sum of columnaaa(2) = sum(posY.*imgY); % E(x)*sumaaa(3) = sum(posY.*posY.*imgY); % E(x^2)*sumaaa(4) = aaa(1)*aaa(3)-aaa(2)^2; %V*sum^2stt(2) = aaa(2)/aaa(1);stt(6) = sqrt(aaa(4))/aaa(1);[aa bb] = max(imgY);stt(4) = bb;
